const int menuCount = 5;
const char* menuItems[menuCount] = {
  "Pomodoro 10s", 
  "Pomodoro 15s", 
  "Pomodoro 20s", 
  "Pomodoro 25s", 
  "Info"
};

int menuIndex = 1;
